import { Effect, Context, Layer, Data, pipe } from "effect";

interface DomainEvent { readonly type: string; readonly at: number; readonly payload: unknown }
interface Command { readonly aggregateId: string; readonly op: "deposit" | "withdraw"; readonly amount: number }

class StoreError extends Data.TaggedError("StoreError")<{ readonly msg: string }> {}
class InvariantError extends Data.TaggedError("InvariantError")<{ readonly msg: string }> {}

interface EventStore {
  readonly load: (id: string) => Effect.Effect<ReadonlyArray<DomainEvent>, StoreError>
  readonly append: (id: string, evs: ReadonlyArray<DomainEvent>) => Effect.Effect<void, StoreError>
}
const EventStore = Context.GenericTag<EventStore>("app/EventStore");

const balanceOf = (evs: ReadonlyArray<DomainEvent>): number =>
  evs.reduce((acc, e) => acc + (e.type === "Deposited" ? (e.payload as { n: number }).n : -(e.payload as { n: number }).n), 0);

const handle = (cmd: Command): Effect.Effect<DomainEvent, StoreError | InvariantError, EventStore> =>
  Effect.gen(function* () {
    const store = yield* EventStore;
    const history = yield* store.load(cmd.aggregateId);
    const bal = balanceOf(history);
    if (cmd.op === "withdraw" && bal < cmd.amount) {
      return yield* Effect.fail(new InvariantError({ msg: "overdraft" }));
    }
    const ev: DomainEvent = { type: cmd.op === "deposit" ? "Deposited" : "Withdrew", at: Date.now(), payload: { n: cmd.amount } };
    yield* store.append(cmd.aggregateId, [ev]);
    return ev;
  });

const InMemory = Layer.succeed(EventStore, {
  load: () => Effect.succeed<ReadonlyArray<DomainEvent>>([]),
  append: () => Effect.succeed(undefined),
});

export const program = pipe(handle({ aggregateId: "acc-1", op: "deposit", amount: 50 }), Effect.provide(InMemory));
```

