import { Effect, Context, Data, pipe } from "effect";

interface OrderEvent { readonly _tag: "Placed" | "Cancelled"; readonly amount: number }
interface PlaceOrder { readonly id: string; readonly amount: number }

class AlreadyPlaced extends Data.TaggedError("AlreadyPlaced")<{ readonly id: string }> {}
class StoreError extends Data.TaggedError("StoreError")<{ readonly cause: unknown }> {}

interface Store {
  readonly load: (id: string) => Effect.Effect<ReadonlyArray<OrderEvent>, StoreError>
  readonly append: (id: string, ev: OrderEvent) => Effect.Effect<void, StoreError>
}
const Store = Context.GenericTag<Store>("app/OrderStore");

const fold = (evs: ReadonlyArray<OrderEvent>) =>
  evs.reduce((s, e) => (e._tag === "Placed" ? { ...s, placed: true } : s), { placed: false });

export const place = (cmd: PlaceOrder): Effect.Effect<OrderEvent, StoreError | AlreadyPlaced, Store> =>
  Effect.gen(function* () {
    const s = yield* Store;
    const state = fold(yield* s.load(cmd.id));
    if (state.placed) return yield* Effect.fail(new AlreadyPlaced({ id: cmd.id }));
    const ev: OrderEvent = { _tag: "Placed", amount: cmd.amount };
    yield* pipe(s.append(cmd.id, ev), Effect.tap(() => Effect.logInfo(`placed ${cmd.id}`)));
    return ev;
  });
```

An event-sourcing command handler is a pure decision function wrapped in three effects: load the event stream, fold it to a snapshot, then append the new event(s). Errors are tagged so the caller can discriminate storage failures from domain invariant violations. Using `Effect.gen` keeps the load -> decide -> append sequence readable while the `E` channel collects every tagged error that can surface.

