interface CartEvent { readonly _tag: "Added" | "Checked"; readonly sku?: string }
interface AddItem { readonly cartId: string; readonly sku: string }

class CheckedAlready extends Data.TaggedError("CheckedAlready")<{ readonly id: string }> {}
class IO extends Data.TaggedError("IO")<{ readonly cause: unknown }> {}

interface Store {
