    const events = yield* store.load(cmd.cartId);
    if (events.some((e) => e._tag === "Checked")) {
      return yield* Effect.fail(new CheckedAlready({ id: cmd.cartId }));
    }
    const ev: CartEvent = { _tag: "Added", sku: cmd.sku };
    yield* store.append(cmd.cartId, ev);
    return ev;
