import { Effect, Context, Data } from "effect";

interface E { readonly _tag: "Did"; readonly n: number }
class Cap extends Data.TaggedError("Cap")<{ readonly at: number }> {}
class IO extends Data.TaggedError("IO")<{ readonly cause: unknown }> {}

interface Store {
  readonly load: () => Effect.Effect<ReadonlyArray<E>, IO>
  readonly append: (e: E) => Effect.Effect<void, IO>
}
const Store = Context.GenericTag<Store>("app/Store");

// pure core: no Effect, trivially testable
export const decide = (evs: ReadonlyArray<E>): E | Cap =>
  evs.length > 5 ? new Cap({ at: evs.length }) : { _tag: "Did", n: evs.length + 1 };

export const handle = (): Effect.Effect<E, IO | Cap, Store> =>
  Effect.gen(function* () {
    const s = yield* Store;
    const out = decide(yield* s.load());
    if (out instanceof Cap) return yield* Effect.fail(out);
    yield* s.append(out);
    return out;
  });
