import { Effect, Schedule, Data, pipe } from "effect";

class Transient extends Data.TaggedError("Transient")<{ readonly job: number }> {}

const work = (n: number): Effect.Effect<number, Transient> =>
  pipe(
    Effect.sync(() => n * 2),
    Effect.tap((v) => Effect.logInfo(`done ${v}`)),
  );

const retryN = Schedule.recurs(3);

export const runAll = (jobs: ReadonlyArray<number>): Effect.Effect<ReadonlyArray<number>, Transient> =>
  Effect.forEach(jobs, (n) => Effect.retry(work(n), retryN), { concurrency: 8 });
```

`Effect.forEach(items, f)` defaults to sequential execution — each step waits for the previous. Passing `{ concurrency: N }` launches up to N fibers simultaneously; `"unbounded"` ignores the cap. Because each fiber has its own error channel, we can wrap the per-item effect with `Effect.retry` before forEach sees it, so one transient failure does not abort the whole batch until retries are exhausted.

