import { Effect, Queue, Context, Data, pipe } from "effect";

interface Msg { readonly id: string; readonly body: string }
class PersistError extends Data.TaggedError("PersistError")<{ readonly id: string }> {}

interface Store { readonly save: (m: Msg) => Effect.Effect<void, PersistError> }
const Store = Context.GenericTag<Store>("app/Store");

export const worker = (q: Queue.Queue<Msg>): Effect.Effect<void, PersistError, Store> =>
  Effect.gen(function* () {
    const store = yield* Store;
    while (true) {
      const m = yield* Queue.take(q);
      yield* pipe(store.save(m), Effect.tap(() => Effect.logInfo(`persisted ${m.id}`)));
    }
  });

export const program = Effect.gen(function* () {
  const q = yield* Queue.bounded<Msg>(128);
  yield* Queue.offer(q, { id: "1", body: "hello" });
  yield* Effect.fork(worker(q));
});
```

```typescript
import { Effect, Queue, Data, pipe } from "effect";

interface Evt { readonly seq: number }
class WriteFail extends Data.TaggedError("WriteFail")<{ readonly seq: number }> {}

const persist = (e: Evt): Effect.Effect<void, WriteFail> =>
  pipe(
    Effect.sync(() => void 0),
    Effect.tap(() => Effect.logInfo(`wrote ${e.seq}`)),
  );

export const pipeline = Effect.gen(function* () {
  // bounded(8) blocks the producer when the queue is full — this is back-pressure
  const q = yield* Queue.bounded<Evt>(8);
  const consumer = Effect.forever(Effect.flatMap(Queue.take(q), persist));
  yield* Effect.fork(consumer);
  for (let i = 0; i < 10; i++) yield* Queue.offer(q, { seq: i });
});
```

A persistent queue writes every enqueue to a durable store before the offer resolves, and the consumer only removes the record after the downstream effect commits. If the worker crashes mid-flight, the next start-up rehydrates unprocessed records back onto the in-memory Queue. Effect's `Queue` provides the in-memory runtime buffer; the persistence boundary is just a Layer that wraps `offer`/`take` with store calls inside `Effect.gen`.

```typescript
import { Effect, Queue, Context, Data } from "effect";

interface Rec { readonly id: string; readonly body: string }
class StoreErr extends Data.TaggedError("StoreErr")<{ readonly cause: unknown }> {}

interface Store {
  readonly write: (r: Rec) => Effect.Effect<void, StoreErr>
  readonly ack: (id: string) => Effect.Effect<void, StoreErr>
}
const Store = Context.GenericTag<Store>("app/Store");

export const enqueue = (q: Queue.Queue<Rec>, r: Rec): Effect.Effect<void, StoreErr, Store> =>
  Effect.gen(function* () {
    yield* (yield* Store).write(r);   // durable first
    yield* Queue.offer(q, r);         // then wake a consumer
  });

export const consume = (q: Queue.Queue<Rec>): Effect.Effect<void, StoreErr, Store> =>
  Effect.gen(function* () {
    const s = yield* Store;
    const r = yield* Queue.take(q);
    yield* s.ack(r.id);
  });
