```typescript
import { Effect, pipe } from "effect";

const hit = (i: number): Effect.Effect<number> =>
  pipe(
    Effect.sleep("50 millis"),
    Effect.as(i),
    Effect.tap((n) => Effect.logInfo(`done ${n}`)),
  );

export const rateLimited = Effect.gen(function* () {
  const sem = yield* Effect.makeSemaphore(2);
  // withPermits(1) acquires exactly one permit for the duration of `hit(i)`
  const runs = [1, 2, 3, 4, 5].map((i) => sem.withPermits(1)(hit(i)));
  return yield* Effect.all(runs, { concurrency: "unbounded" });
});
```

`Effect.all(xs, { concurrency: 5 })` bounds just that single batch — two independent call sites can still each run 5 in parallel for a total of 10. A `Semaphore` is a shared resource: every call site acquires permits from the same pool, so the global cap holds regardless of how many batches are open at once. You create it once, close over it in the client closure, and `withPermits(1)` wraps each outbound effect.

