import { Effect, Scope, Data, pipe } from "effect";

interface DB { readonly name: string }
class ConnErr extends Data.TaggedError("ConnErr")<{ readonly cause: unknown }> {}

const acquire: Effect.Effect<DB, ConnErr> =
  pipe(Effect.succeed({ name: "pg" }), Effect.tap(() => Effect.logInfo("DB opened")));

const release = (db: DB): Effect.Effect<void> =>
  Effect.sync(() => console.log(`closing ${db.name}`));

const scopedDb: Effect.Effect<DB, ConnErr, Scope.Scope> = Effect.acquireRelease(acquire, release);

export const program = Effect.scoped(
  Effect.gen(function* () {
    const db = yield* scopedDb;
    yield* Effect.logInfo(`using ${db.name}`);
    // finalizer runs on success, failure, AND interruption
    return db.name;
  }),
);
