```typescript
import { Effect, Scope, pipe } from "effect";

type Unsub = () => void
const subscribe = (): Effect.Effect<Unsub> =>
  Effect.sync(() => {
    const off = () => console.log("unsubscribed");
    return off;
  });

// Effect.addFinalizer registers a cleanup with the enclosing Scope.
// Effect.scoped closes the scope whichever way the program exits.
export const listener = Effect.scoped(
  pipe(
    Effect.gen(function* () {
      const off = yield* subscribe();
      yield* Effect.addFinalizer(() => Effect.sync(off));
      return "ready";
    }),
  ),
);
```

A `Scope` is a stack of finalizers. Every `Effect.acquireRelease` pushes a release onto the current scope at acquisition time. When `Effect.scoped` closes the scope — on success, typed failure, OR interruption — the runtime pops finalizers LIFO and runs them, collecting any errors but never skipping one. That ordering means the most recently opened resource is closed first, matching `try/finally` nesting without the syntactic burden.

```typescript
import { Effect, Scope, pipe } from "effect";

interface File { readonly fd: number }
interface Lock { readonly id: string }

const openFile: Effect.Effect<File, never, Scope.Scope> =
  Effect.acquireRelease(Effect.succeed({ fd: 3 }), (f) => Effect.sync(() => console.log(`close ${f.fd}`)));

const takeLock: Effect.Effect<Lock, never, Scope.Scope> =
  Effect.acquireRelease(Effect.succeed({ id: "l1" }), (l) => Effect.sync(() => console.log(`release ${l.id}`)));

export const program = Effect.scoped(
  Effect.gen(function* () {
    const f = yield* openFile;     // opened first
    const l = yield* takeLock;     // opened second
    yield* Effect.logInfo(`work with ${f.fd} + ${l.id}`);
    // on exit: release LOCK, then close FILE
    return [f.fd, l.id] as const;
  }),
);
```

