import { Effect, Data, pipe } from "effect";

interface Ev { readonly _tag: "Up" | "Down" | "Bad"; readonly n: number }
class Corrupt extends Data.TaggedError("Corrupt")<{ readonly at: number }> {}

const step = (acc: number, e: Ev): Effect.Effect<number, Corrupt> => {
  if (e._tag === "Bad") return Effect.fail(new Corrupt({ at: e.n }));
  return Effect.succeed(e._tag === "Up" ? acc + e.n : acc - e.n);
};

export const replay = (evs: ReadonlyArray<Ev>): Effect.Effect<number, Corrupt> =>
  evs.reduce<Effect.Effect<number, Corrupt>>(
    (acc, e) => pipe(acc, Effect.flatMap((s) => step(s, e))),
    Effect.succeed(0),
  );
